sp_widget.client_script:
api.controller = function ($scope, scmBreadcrumbsManager) {
    const c = this;
    const defaultBreadcrumbs = [
        { title: "Home", link: "?id=homepage", icon: "icon-home" },
    ];

    function normalizeForView(items) {
        if (!Array.isArray(items) || !items.length) {
            return angular.copy(defaultBreadcrumbs);
        }

        return items
            .filter((item) => !!item)
            .map((item) => {
                const title = String(item.title || "");
                return {
                    title: title,
                    link: String(item.link || "#"),
                    icon:
                        item.icon || title.toLowerCase() === "home"
                            ? String(item.icon || "icon-home")
                            : "",
                };
            });
    }

    c.breadcrumbs = normalizeForView(scmBreadcrumbsManager.get());

    const unsubscribe = $scope.$on(
        "scm-navigation-breadcrumbs_set",
        function (event, breadcrumbs) {
            c.breadcrumbs = normalizeForView(breadcrumbs);
        },
    );

    $scope.$on("$destroy", function () {
        unsubscribe();
    });
};
